import json
import jwt
from functools import wraps
from flask import request, jsonify
import datetime as dt


def jwt_auth(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        # token is passed in the Authorization header by users. 
        try:
            token = request.headers['Authorization']
        except Exception:
            return jsonify({'Error': 'Invalid token'}), 401
        try:
            # Decode token using a secret key. 
            data = jwt.decode(token, SECRET_KEY)
        except Exception as e:
            print('Exception : ',e )
            return jsonify({"Error":str(e)}), 403

        # If JWT payload contains an exp field, compare it with current time. 
        if 'exp' in data and dt.datetime.fromtimestamp(data['exp']) < \
                dt.datetime.now():
            print('Token expired')
            return jsonify({'Error': 'Token expired'}), 401
        return func(*args, **kwargs)
    return wrapper

